import { useTranslation } from "react-i18next";

import { ArrowLeft, MapPin, Eye, Megaphone, Gift, Mail } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Separator } from "@/components/ui/separator";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useSmartBack } from "@/hooks/useSmartBack";

const AdSpace = () => {
  const { i18n } = useTranslation();
  const goBack = useSmartBack("/");
  const lang = i18n.language;

  const { data: rentalConfig } = useQuery({
    queryKey: ["rental-banner-config"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("site_settings")
        .select("rental_banner_email")
        .single();
      if (error) throw error;
      return data;
    },
    staleTime: 5 * 60 * 1000,
  });

  const title = lang === "zh" ? "广告位招租" : lang === "pt" ? "Espaço Publicitário" : "Advertising Space";
  const subtitle = lang === "zh"
    ? "在数千家餐厅详情页面展示您的品牌"
    : lang === "pt"
      ? "Exiba sua marca em milhares de páginas de restaurantes"
      : "Showcase your brand across thousands of restaurant pages";

  const features = [
    {
      icon: MapPin,
      title: lang === "zh" ? "精准投放位置" : lang === "pt" ? "Posicionamento Preciso" : "Precise Placement",
      desc: lang === "zh"
        ? "广告展示在餐厅详情页面，位于菜品图片下方、地图上方的黄金位置，确保最大曝光率。"
        : lang === "pt"
          ? "Os anúncios são exibidos nas páginas de detalhes dos restaurantes, numa posição privilegiada entre a galeria de pratos e o mapa."
          : "Ads are displayed on restaurant detail pages, in a prime position between the dish gallery and the map for maximum visibility.",
    },
    {
      icon: Eye,
      title: lang === "zh" ? "覆盖未认领商店" : lang === "pt" ? "Cobertura de Lojas Não Reivindicadas" : "Unclaimed Store Coverage",
      desc: lang === "zh"
        ? "广告仅在未被商家认领的商店页面展示，覆盖数千家餐厅页面，获得巨大的潜在曝光量。"
        : lang === "pt"
          ? "Os anúncios são exibidos apenas em páginas de lojas não reivindicadas, cobrindo milhares de páginas de restaurantes."
          : "Ads are shown only on unclaimed store pages, covering thousands of restaurant pages for massive potential exposure.",
    },
    {
      icon: Megaphone,
      title: lang === "zh" ? "按国家精准投放" : lang === "pt" ? "Segmentação por País" : "Country-Level Targeting",
      desc: lang === "zh"
        ? "支持按国家精准投放广告，您可以选择在特定国家的餐厅页面展示广告，实现精准营销。"
        : lang === "pt"
          ? "Suporte para segmentação por país, permitindo exibir anúncios em páginas de restaurantes de países específicos."
          : "Support country-level ad targeting, allowing you to display ads on restaurant pages in specific countries for precise marketing.",
    },
    {
      icon: Gift,
      title: lang === "zh" ? "首月免费试用" : lang === "pt" ? "Primeiro Mês Grátis" : "First Month Free",
      desc: lang === "zh"
        ? "新广告主享受首月免费投放！零风险体验广告效果，满意后再续费。"
        : lang === "pt"
          ? "Novos anunciantes aproveitam o primeiro mês grátis! Experimente sem risco e renove apenas se estiver satisfeito."
          : "New advertisers enjoy the first month free! Experience ad performance risk-free and renew only if satisfied.",
    },
  ];

  const steps = lang === "zh"
    ? ["联系我们的广告团队", "提供广告素材（图片 + 链接）", "选择投放国家和时间", "审核通过后自动上线", "首月免费，按月续费"]
    : lang === "pt"
      ? ["Contacte a nossa equipa de publicidade", "Forneça os materiais (imagem + link)", "Selecione países e período", "Aprovação e publicação automática", "Primeiro mês grátis, renovação mensal"]
      : ["Contact our advertising team", "Provide ad materials (image + link)", "Select target countries and period", "Auto-publish after approval", "First month free, monthly renewal"];

  const contactEmail = rentalConfig?.rental_banner_email || "ads@xiaoxiong.pt";

  return (
    <div className="container mx-auto px-4 py-8 max-w-4xl">
      {/* Back button */}
      <Button variant="ghost" size="sm" onClick={goBack} className="mb-6">
        <ArrowLeft className="h-4 w-4 mr-1" />
        {lang === "zh" ? "返回" : lang === "pt" ? "Voltar" : "Back"}
      </Button>

      {/* Hero */}
      <div className="text-center mb-12">
        <Badge className="mb-4 text-sm px-4 py-1" variant="secondary">
          {lang === "zh" ? "🎉 首月免费" : lang === "pt" ? "🎉 Primeiro Mês Grátis" : "🎉 First Month Free"}
        </Badge>
        <h1 className="text-3xl md:text-4xl font-bold mb-3">{title}</h1>
        <p className="text-lg text-muted-foreground max-w-2xl mx-auto">{subtitle}</p>
      </div>

      {/* Features */}
      <div className="grid md:grid-cols-2 gap-6 mb-12">
        {features.map((f, i) => (
          <Card key={i} className="border-border/50 hover:shadow-md transition-shadow">
            <CardContent className="p-6">
              <div className="flex items-start gap-4">
                <div className="rounded-lg bg-primary/10 p-2.5 shrink-0">
                  <f.icon className="h-5 w-5 text-primary" />
                </div>
                <div>
                  <h3 className="font-semibold mb-1.5">{f.title}</h3>
                  <p className="text-sm text-muted-foreground leading-relaxed">{f.desc}</p>
                </div>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>

      <Separator className="mb-12" />

      {/* Ad Placement Preview */}
      <div className="mb-12">
        <h2 className="text-2xl font-bold text-center mb-6">
          {lang === "zh" ? "广告展示位置" : lang === "pt" ? "Posição do Anúncio" : "Ad Placement"}
        </h2>
        <div className="max-w-sm mx-auto">
          <div className="border border-border rounded-xl overflow-hidden bg-card">
            {/* Mock restaurant header */}
            <div className="bg-muted/50 p-4 text-center">
              <div className="h-3 w-24 bg-muted rounded mx-auto mb-2" />
              <div className="h-2 w-32 bg-muted rounded mx-auto" />
            </div>
            {/* Mock dish gallery */}
            <div className="p-3 flex gap-2">
              <div className="h-16 w-16 bg-muted rounded flex-shrink-0" />
              <div className="h-16 w-16 bg-muted rounded flex-shrink-0" />
              <div className="h-16 w-16 bg-muted rounded flex-shrink-0" />
            </div>
            {/* AD POSITION highlighted */}
            <div className="mx-3 mb-3">
              <div className="border-2 border-dashed border-primary rounded-lg p-4 text-center bg-primary/5 relative">
                <span className="absolute top-1 left-2 text-[10px] text-primary font-medium">
                  {lang === "zh" ? "广告" : "AD"}
                </span>
                <Megaphone className="h-6 w-6 text-primary mx-auto mb-1.5" />
                <p className="text-xs font-medium text-primary">
                  {lang === "zh" ? "您的广告在这里" : lang === "pt" ? "Seu anúncio aqui" : "Your ad here"}
                </p>
                <p className="text-[10px] text-muted-foreground mt-0.5">16:9 ratio</p>
              </div>
            </div>
            {/* Mock map */}
            <div className="bg-muted/30 p-4 text-center border-t">
              <div className="h-2 w-12 bg-muted rounded mx-auto mb-1" />
              <div className="h-16 bg-muted rounded" />
            </div>
          </div>
        </div>
      </div>

      <Separator className="mb-12" />

      {/* How it works */}
      <div className="mb-12">
        <h2 className="text-2xl font-bold text-center mb-8">
          {lang === "zh" ? "如何投放广告" : lang === "pt" ? "Como Anunciar" : "How to Advertise"}
        </h2>
        <div className="max-w-lg mx-auto space-y-4">
          {steps.map((step, i) => (
            <div key={i} className="flex items-start gap-3">
              <div className="flex items-center justify-center h-7 w-7 rounded-full bg-primary text-primary-foreground text-sm font-bold shrink-0 mt-0.5">
                {i + 1}
              </div>
              <div className="flex items-center gap-2 pt-1">
                <p className="text-sm">{step}</p>
                {i === 4 && <Badge variant="secondary" className="text-[10px]">🎉</Badge>}
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* CTA */}
      <Card className="border-primary/20 bg-primary/5">
        <CardContent className="p-8 text-center">
          <h3 className="text-xl font-bold mb-2">
            {lang === "zh" ? "立即开始投放" : lang === "pt" ? "Comece a Anunciar Agora" : "Start Advertising Now"}
          </h3>
          <p className="text-muted-foreground mb-6 text-sm">
            {lang === "zh"
              ? "联系我们的广告团队，享受首月免费优惠"
              : lang === "pt"
                ? "Contacte a nossa equipa e aproveite o primeiro mês grátis"
                : "Contact our team and enjoy the first month free"}
          </p>
          <Button size="lg" asChild>
            <a href={`mailto:${contactEmail}?subject=${encodeURIComponent(lang === "zh" ? "广告位咨询" : "Ad Space Inquiry")}`}>
              <Mail className="h-4 w-4 mr-2" />
              {contactEmail}
            </a>
          </Button>
        </CardContent>
      </Card>
    </div>
  );
};

export default AdSpace;
